external_knowledge:
- 'long-term members' refers to individuals over the age of 50;
- 'still active' means their status is 'OPEN';
- 'listed by their most recent sign-ups' indicates sorting by the date of registration in descending order.

sql:
SELECT i.first_name, i.last_name, i.sex
FROM individuals i
JOIN service_provision sp ON i.individual_id = sp.individual_id;

SELECT individual_id, COUNT(*) AS num_services
FROM service_provision
GROUP BY individual_id;

SELECT COUNT(DISTINCT individual_id) 
FROM access_logs 
WHERE access_type = 'edit';

SELECT organisation_name, contact_email, address 
FROM organisations 
WHERE organisation_id = 1;

SELECT COUNT(DISTINCT individual_id) AS IndividualsUsedService2022
FROM service_provision
WHERE provision_date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT * 
FROM families 
WHERE family_size > 10;

SELECT DISTINCT first_name, last_name
FROM individuals
WHERE status = 'OPEN';

SELECT * 
FROM individuals 
ORDER BY first_name ASC;

SELECT COUNT(individual_id) AS member_count, organisation_id
FROM individuals
GROUP BY organisation_id;

SELECT family_id, primary_contact_name
FROM families
WHERE family_size > 10;
